-- ============================================================
-- CRM import, part 2: items (Изделия) linked to imported orders
-- Source: ERP - УП (4 sheets)
-- Idempotent: unique key = order number + item name. Safe to re-run.
-- Items to insert: 1076
-- Per item: record + link to order (zakazy) + link to its project
-- (proekty), client copied from the project's client, project manager
-- resolved by user full name.
-- ============================================================

BEGIN;

WITH ord AS (
  SELECT er.id FROM entity_records er
  WHERE er.entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND er.values_json->>'order_number'='2973'
  ORDER BY er.id LIMIT 1
), proj AS (
  SELECT rl.target_record_id AS id FROM record_links rl JOIN ord ON rl.source_record_id=ord.id
  WHERE rl.relation_id=(SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects')) LIMIT 1
), new_item AS (
  INSERT INTO entity_records (entity_id, values_json)
  SELECT (SELECT id FROM entities WHERE entity_key='items'), jsonb_strip_nulls(jsonb_build_object('item_name', 'מעקה מרפסת קומה 1.2 צד פנימי וצד חיצוני', 'quantity', 89.04, 'unit_price', 870, 'designer_cost', 534.24, 'mnf_cost_unit', 130, 'production_finish_date', '2026-01-02', 'project_manager', (SELECT id FROM users WHERE email='baruch.sd.davidov@gmail.com'), 'client', (SELECT p.values_json->'client' FROM entity_records p WHERE p.id=proj.id)))
  FROM ord LEFT JOIN proj ON true
  WHERE NOT EXISTS (
    SELECT 1 FROM entity_records it
    JOIN record_links l ON l.source_record_id=it.id AND l.relation_id=(SELECT id FROM relations WHERE relation_key='zakazy' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='orders')) AND l.target_record_id=ord.id
    WHERE it.entity_id=(SELECT id FROM entities WHERE entity_key='items') AND it.values_json->>'item_name'='מעקה מרפסת קומה 1.2 צד פנימי וצד חיצוני'
  )
  RETURNING id
), lnk_ord AS (
  INSERT INTO record_links (relation_id, relation_type, source_record_id, target_record_id)
  SELECT (SELECT id FROM relations WHERE relation_key='zakazy' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='orders')), 'many_to_one', ni.id, ord.id FROM new_item ni, ord
  ON CONFLICT DO NOTHING RETURNING 1
)
INSERT INTO record_links (relation_id, relation_type, source_record_id, target_record_id)
SELECT (SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects')), 'many_to_one', ni.id, proj.id FROM new_item ni, proj
ON CONFLICT DO NOTHING;

