  WHERE er.entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND er.values_json->>'order_number'='3474'
  ORDER BY er.id LIMIT 1
), proj AS (
  SELECT rl.target_record_id AS id FROM record_links rl JOIN ord ON rl.source_record_id=ord.id
  WHERE rl.relation_id=(SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects')) LIMIT 1
), new_item AS (
  INSERT INTO entity_records (entity_id, values_json)
  SELECT (SELECT id FROM entities WHERE entity_key='items'), jsonb_strip_nulls(jsonb_build_object('item_name', 'צביעה סביבה ימית 3 שכבות', 'quantity', 1.23, 'unit_price', 250, 'project_manager', (SELECT id FROM users WHERE email='evgeni.sd.davidov@gmail.com'), 'client', (SELECT p.values_json->'client' FROM entity_records p WHERE p.id=proj.id)))
  FROM ord LEFT JOIN proj ON true
  WHERE NOT EXISTS (
    SELECT 1 FROM entity_records it
    JOIN record_links l ON l.source_record_id=it.id AND l.relation_id=(SELECT id FROM relations WHERE relation_key='zakazy' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='orders')) AND l.target_record_id=ord.id
    WHERE it.entity_id=(SELECT id FROM entities WHERE entity_key='items') AND it.values_json->>'item_name'='צביעה סביבה ימית 3 שכבות'
  )
  RETURNING id
), lnk_ord AS (
  INSERT INTO record_links (relation_id, relation_type, source_record_id, target_record_id)
  SELECT (SELECT id FROM relations WHERE relation_key='zakazy' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='orders')), 'many_to_one', ni.id, ord.id FROM new_item ni, ord
  ON CONFLICT DO NOTHING RETURNING 1
)
