-- Summary (informational) --------------------------------------
DO $$
DECLARE n_items int; n_ord int; n_proj int; n_client int; n_pm int;
BEGIN
  SELECT count(*) INTO n_items FROM entity_records WHERE entity_id=(SELECT id FROM entities WHERE entity_key='items');
  SELECT count(DISTINCT rl.source_record_id) INTO n_ord FROM record_links rl WHERE rl.relation_id=(SELECT id FROM relations WHERE relation_key='zakazy' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='orders'));
  SELECT count(DISTINCT rl.source_record_id) INTO n_proj FROM record_links rl WHERE rl.relation_id=(SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='items') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects'));
  SELECT count(*) INTO n_client FROM entity_records WHERE entity_id=(SELECT id FROM entities WHERE entity_key='items') AND values_json ? 'client';
  SELECT count(*) INTO n_pm FROM entity_records WHERE entity_id=(SELECT id FROM entities WHERE entity_key='items') AND values_json ? 'project_manager';
  RAISE NOTICE 'Items total: %, linked to order: %, linked to project: %, with client: %, with project manager: %', n_items, n_ord, n_proj, n_client, n_pm;
END $$;

COMMIT;
